import { describe, it, expect, beforeEach, jest } from '@jest/globals';
import { render, screen, waitFor, fireEvent } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import '@testing-library/jest-dom';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import ModularBillForm from '../../client/src/components/bill-management/ModularBillForm';
import { Bill } from '../../shared/schema';

/**
 * Comprehensive test suite for Bills Template Workflow
 * Tests all aspects of the template-based bill creation including:
 * - Auto-generated bill template functionality
 * - Recurrence checkbox pre-checking for auto-generated bills
 * - Template safeguards (auto-save disabled, delete button hidden)
 * - Form data population from template bills
 * - POST-only mutations for template mode
 */

// Mock the language provider
jest.mock('../../client/src/lib/i18n', () => ({
  useLanguage: () => ({
    language: 'en',
    t: (key: string) => key,
  }),
}));

// Mock the toast hook
jest.mock('../../client/src/hooks/use-toast', () => ({
  useToast: () => ({
    toast: jest.fn(),
  }),
}));

// Mock fetch globally
global.fetch = jest.fn();

describe('Bills Template Workflow', () => {
  let queryClient: QueryClient;

  beforeEach(() => {
    queryClient = new QueryClient({
      defaultOptions: {
        queries: { retry: false },
        mutations: { retry: false },
      },
    });
    
    // Reset fetch mock
    (global.fetch as jest.Mock).mockReset();
    
    // Mock successful responses by default
    (global.fetch as jest.Mock).mockResolvedValue({
      ok: true,
      json: async () => ({ success: true }),
    });
  });

  describe('Auto-Generated Bill Template Creation', () => {
    it('should pre-check recurrence checkbox when creating from auto-generated bill', async () => {
      const autoGeneratedBill: Partial<Bill> = {
        id: 'auto-gen-123',
        buildingId: 'building-123',
        title: 'test1',
        description: 'Auto-generated test bill',
        category: 'maintenance',
        vendor: 'vendor 1',
        paymentType: 'unique', // Auto-generated bills have paymentType='unique'
        costs: ['1000.00'],
        totalAmount: '1000.00',
        startDate: '2026-01-29',
        status: 'draft',
        isAutoGenerated: true, // Key flag for pre-checking
        sourceTemplateId: 'source-bill-id',
        autoGeneratedLabel: 'Auto 2026',
      };

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={autoGeneratedBill as Bill}
            isTemplate={true}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      await waitFor(() => {
        // The recurrence checkbox should be checked
        const recurrenceCheckbox = screen.getByRole('checkbox', {
          name: /generate bills for next year automatically/i,
        });
        expect(recurrenceCheckbox).toBeChecked();
      });
    });

    it('should NOT pre-check recurrence for regular bills', async () => {
      const regularBill: Partial<Bill> = {
        id: 'regular-123',
        buildingId: 'building-123',
        title: 'test2',
        description: 'Regular bill',
        category: 'utilities',
        vendor: 'vendor 2',
        paymentType: 'unique',
        costs: ['500.00'],
        totalAmount: '500.00',
        startDate: '2025-01-15',
        status: 'draft',
        isAutoGenerated: false,
      };

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={regularBill as Bill}
            isTemplate={true}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      await waitFor(() => {
        const recurrenceCheckbox = screen.getByRole('checkbox', {
          name: /generate bills for next year automatically/i,
        });
        expect(recurrenceCheckbox).not.toBeChecked();
      });
    });

    it('should populate form fields with template bill data', async () => {
      const templateBill: Partial<Bill> = {
        id: 'template-123',
        buildingId: 'building-123',
        title: 'Insurance Premium',
        description: 'Annual building insurance',
        category: 'insurance',
        vendor: 'Insurance Corp',
        paymentType: 'recurrent',
        costs: ['2500.00'],
        totalAmount: '2500.00',
        startDate: '2025-06-01',
        status: 'active',
        isAutoGenerated: true,
        autoGeneratedLabel: 'Auto 2026',
      };

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={templateBill as Bill}
            isTemplate={true}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      await waitFor(() => {
        // Verify form fields are populated
        expect(screen.getByDisplayValue('Insurance Premium')).toBeInTheDocument();
        expect(screen.getByDisplayValue('Annual building insurance')).toBeInTheDocument();
        expect(screen.getByDisplayValue('Insurance Corp')).toBeInTheDocument();
        expect(screen.getByDisplayValue('2500.00')).toBeInTheDocument();
      });
    });

    it('should show "Create Bill from Template" header when isTemplate=true', async () => {
      const templateBill: Partial<Bill> = {
        id: 'template-456',
        buildingId: 'building-123',
        title: 'Test Bill',
        category: 'other',
        paymentType: 'unique',
        costs: ['100.00'],
        totalAmount: '100.00',
        startDate: '2025-01-01',
        isAutoGenerated: true,
      };

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={templateBill as Bill}
            isTemplate={true}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      await waitFor(() => {
        expect(screen.getByText(/create.*from.*template/i)).toBeInTheDocument();
      });
    });
  });

  describe('Template Safeguards', () => {
    it('should hide delete button when isTemplate=true', async () => {
      const templateBill: Partial<Bill> = {
        id: 'template-789',
        buildingId: 'building-123',
        title: 'Test Bill',
        category: 'maintenance',
        paymentType: 'unique',
        costs: ['200.00'],
        totalAmount: '200.00',
        startDate: '2025-02-01',
        isAutoGenerated: true,
      };

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={templateBill as Bill}
            isTemplate={true}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      await waitFor(() => {
        // Delete button should not be present
        const deleteButton = screen.queryByRole('button', { name: /delete/i });
        expect(deleteButton).not.toBeInTheDocument();
      });
    });

    it('should use POST endpoint for template bills even when bill has ID', async () => {
      const templateBill: Partial<Bill> = {
        id: 'existing-bill-id',
        buildingId: 'building-123',
        title: 'Template Bill',
        category: 'utilities',
        paymentType: 'unique',
        costs: ['300.00'],
        totalAmount: '300.00',
        startDate: '2025-03-01',
        isAutoGenerated: true,
      };

      const user = userEvent.setup();

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={templateBill as Bill}
            isTemplate={true}
            onSuccess={jest.fn()}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      await waitFor(() => {
        const saveButton = screen.getByRole('button', { name: /save|create/i });
        expect(saveButton).toBeInTheDocument();
      });

      // Submit the form
      const saveButton = screen.getByRole('button', { name: /save|create/i });
      await user.click(saveButton);

      await waitFor(() => {
        // Verify POST was used, not PUT
        expect(global.fetch).toHaveBeenCalledWith(
          expect.stringContaining('/api/bills'),
          expect.objectContaining({
            method: 'POST',
          })
        );
        
        // Verify it did NOT use PUT to the bill's ID
        expect(global.fetch).not.toHaveBeenCalledWith(
          expect.stringContaining(`/api/bills/${templateBill.id}`),
          expect.any(Object)
        );
      });
    });
  });

  describe('Bill Form Data Validation', () => {
    it('should validate required fields before submission', async () => {
      const user = userEvent.setup();

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm buildingId="building-123" />
        </QueryClientProvider>
      );

      // Try to submit without filling required fields
      const saveButton = screen.getByRole('button', { name: /save|create/i });
      await user.click(saveButton);

      await waitFor(() => {
        // Should show validation errors
        expect(screen.getByText(/required/i)).toBeInTheDocument();
      });
    });

    it('should map recurrence checkbox to paymentType correctly', async () => {
      const user = userEvent.setup();

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm buildingId="building-123" />
        </QueryClientProvider>
      );

      // Fill in required fields
      const titleInput = screen.getByLabelText(/title/i);
      await user.type(titleInput, 'Test Recurrent Bill');

      const categorySelect = screen.getByLabelText(/category/i);
      await user.click(categorySelect);
      await user.click(screen.getByText('Maintenance'));

      // Check recurrence
      const recurrenceCheckbox = screen.getByRole('checkbox', {
        name: /generate bills for next year automatically/i,
      });
      await user.click(recurrenceCheckbox);

      // Submit
      const saveButton = screen.getByRole('button', { name: /save|create/i });
      await user.click(saveButton);

      await waitFor(() => {
        // Verify fetch was called with paymentType='recurrent'
        expect(global.fetch).toHaveBeenCalledWith(
          expect.any(String),
          expect.objectContaining({
            method: 'POST',
            body: expect.stringContaining('"paymentType":"recurrent"'),
          })
        );
      });
    });
  });

  describe('Auto-Generation Workflow Edge Cases', () => {
    it('should handle single payment recurrent bills correctly', async () => {
      const singlePaymentRecurrent: Partial<Bill> = {
        id: 'single-recurrent-123',
        buildingId: 'building-123',
        title: 'Annual Fee',
        category: 'administration',
        vendor: 'Admin Corp',
        paymentType: 'recurrent',
        schedulePayment: undefined,
        costs: ['1200.00'], // Single payment
        totalAmount: '1200.00',
        startDate: '2025-01-01',
        isAutoGenerated: true,
      };

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={singlePaymentRecurrent as Bill}
            isTemplate={true}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      await waitFor(() => {
        // Should pre-check recurrence
        const recurrenceCheckbox = screen.getByRole('checkbox', {
          name: /generate bills for next year automatically/i,
        });
        expect(recurrenceCheckbox).toBeChecked();
        
        // Should show single payment selected
        const singlePaymentRadio = screen.getByRole('radio', { name: /single payment/i });
        expect(singlePaymentRadio).toBeChecked();
      });
    });

    it('should handle multiple payment auto-generated bills', async () => {
      const multiplePaymentBill: Partial<Bill> = {
        id: 'multi-payment-123',
        buildingId: 'building-123',
        title: 'Quarterly Fees',
        category: 'utilities',
        paymentType: 'unique', // Converted from recurrent after generation
        schedulePayment: 'monthly',
        costs: ['500.00', '500.00', '500.00', '500.00'],
        totalAmount: '2000.00',
        startDate: '2025-01-01',
        isAutoGenerated: true,
      };

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={multiplePaymentBill as Bill}
            isTemplate={true}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      await waitFor(() => {
        // Should pre-check recurrence for auto-generated bill
        const recurrenceCheckbox = screen.getByRole('checkbox', {
          name: /generate bills for next year automatically/i,
        });
        expect(recurrenceCheckbox).toBeChecked();
        
        // Should show multiple payments
        const multiplePaymentsRadio = screen.getByRole('radio', {
          name: /multiple payments/i,
        });
        expect(multiplePaymentsRadio).toBeChecked();
      });
    });

    it('should preserve bill data when switching between template and regular mode', async () => {
      const bill: Partial<Bill> = {
        id: 'switch-mode-123',
        buildingId: 'building-123',
        title: 'Switchable Bill',
        category: 'cleaning',
        paymentType: 'unique',
        costs: ['250.00'],
        totalAmount: '250.00',
        startDate: '2025-04-01',
        isAutoGenerated: true,
      };

      const { rerender } = render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={bill as Bill}
            isTemplate={true}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      await waitFor(() => {
        expect(screen.getByDisplayValue('Switchable Bill')).toBeInTheDocument();
      });

      // Rerender without template mode
      rerender(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={bill as Bill}
            isTemplate={false}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      await waitFor(() => {
        // Data should still be present
        expect(screen.getByDisplayValue('Switchable Bill')).toBeInTheDocument();
        expect(screen.getByDisplayValue('250.00')).toBeInTheDocument();
      });
    });
  });

  describe('Success Callbacks and Dialog Management', () => {
    it('should call onSuccess callback after successful bill creation', async () => {
      const onSuccessMock = jest.fn();
      const user = userEvent.setup();

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            buildingId="building-123"
            onSuccess={onSuccessMock}
          />
        </QueryClientProvider>
      );

      // Fill and submit form
      const titleInput = screen.getByLabelText(/title/i);
      await user.type(titleInput, 'Success Test Bill');

      const categorySelect = screen.getByLabelText(/category/i);
      await user.click(categorySelect);
      await user.click(screen.getByText('Other'));

      const saveButton = screen.getByRole('button', { name: /save|create/i });
      await user.click(saveButton);

      await waitFor(() => {
        expect(onSuccessMock).toHaveBeenCalled();
      });
    });

    it('should call onCancel callback when cancel is clicked', async () => {
      const onCancelMock = jest.fn();
      const user = userEvent.setup();

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm buildingId="building-123" onCancel={onCancelMock} />
        </QueryClientProvider>
      );

      const cancelButton = screen.getByRole('button', { name: /cancel/i });
      await user.click(cancelButton);

      expect(onCancelMock).toHaveBeenCalled();
    });
  });

  describe('Form Field Interactions', () => {
    it('should show payment schedule dropdown when recurrence is checked', async () => {
      const user = userEvent.setup();

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm buildingId="building-123" />
        </QueryClientProvider>
      );

      // Initially should not show payment schedule
      expect(screen.queryByLabelText(/payment schedule/i)).not.toBeInTheDocument();

      // Check recurrence
      const recurrenceCheckbox = screen.getByRole('checkbox', {
        name: /generate bills for next year automatically/i,
      });
      await user.click(recurrenceCheckbox);

      await waitFor(() => {
        // Should now show payment schedule
        expect(screen.getByLabelText(/payment schedule/i)).toBeInTheDocument();
      });
    });

    it('should calculate total amount correctly for multiple payments', async () => {
      const user = userEvent.setup();

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm buildingId="building-123" />
        </QueryClientProvider>
      );

      // Select multiple payments
      const multiplePaymentsRadio = screen.getByRole('radio', {
        name: /multiple payments/i,
      });
      await user.click(multiplePaymentsRadio);

      // Add custom payment amounts
      const initialPaymentInput = screen.getByLabelText(/initial payment/i);
      await user.type(initialPaymentInput, '1000');

      const recurringPaymentInput = screen.getByLabelText(/recurring payment/i);
      await user.type(recurringPaymentInput, '500');

      await waitFor(() => {
        // Total should be calculated (1000 + 500 * 11 months = 6500 for yearly)
        const totalDisplay = screen.getByText(/total.*6500/i);
        expect(totalDisplay).toBeInTheDocument();
      });
    });
  });

  describe('Data Persistence and Auto-Save', () => {
    it('should NOT auto-save when isTemplate=true', async () => {
      const user = userEvent.setup();

      const templateBill: Partial<Bill> = {
        id: 'no-autosave-123',
        buildingId: 'building-123',
        title: 'No Auto-Save Bill',
        category: 'maintenance',
        paymentType: 'unique',
        costs: ['100.00'],
        totalAmount: '100.00',
        startDate: '2025-01-01',
        isAutoGenerated: true,
      };

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={templateBill as Bill}
            isTemplate={true}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      // Change a field
      const titleInput = screen.getByDisplayValue('No Auto-Save Bill');
      await user.clear(titleInput);
      await user.type(titleInput, 'Modified Title');

      // Wait a bit to ensure auto-save would have triggered
      await new Promise((resolve) => setTimeout(resolve, 2000));

      // Verify PUT was NOT called (no auto-save)
      expect(global.fetch).not.toHaveBeenCalledWith(
        expect.stringContaining(`/api/bills/${templateBill.id}`),
        expect.objectContaining({ method: 'PUT' })
      );
    });

    it('should auto-save when isTemplate=false for existing bill', async () => {
      const user = userEvent.setup();

      const existingBill: Partial<Bill> = {
        id: 'autosave-123',
        buildingId: 'building-123',
        title: 'Auto-Save Bill',
        category: 'utilities',
        paymentType: 'unique',
        costs: ['200.00'],
        totalAmount: '200.00',
        startDate: '2025-01-01',
        isAutoGenerated: false,
      };

      render(
        <QueryClientProvider client={queryClient}>
          <ModularBillForm
            bill={existingBill as Bill}
            isTemplate={false}
            buildingId="building-123"
          />
        </QueryClientProvider>
      );

      // Change a field
      const titleInput = screen.getByDisplayValue('Auto-Save Bill');
      await user.clear(titleInput);
      await user.type(titleInput, 'Modified Auto-Save');

      // Wait for auto-save debounce (1.5 seconds)
      await waitFor(
        () => {
          expect(global.fetch).toHaveBeenCalledWith(
            expect.stringContaining(`/api/bills/${existingBill.id}`),
            expect.objectContaining({ method: 'PUT' })
          );
        },
        { timeout: 3000 }
      );
    });
  });
});
